@spec mm_unified_spec  src=tests/specs/mm_unified_spec.lua  loc=173  sha=37ed80d  cases=9
@exercises midiManager (h.fm)
@surface   fm:modify, fm:byUuid, fm:notes, fm:assign, fm:ccs, fm:delete, fm:events, fm:add
@harness   mk{seed.notes, seed.ccs}, bareMM

# Intent
  Pin-tests for the unified uuid-addressed write/iter surface on midiManager:
    mm:add(t) → uuid
    mm:assign(uuid, t) → uuid (always the same one: identity never re-keys)
    mm:delete(uuid)
    mm:events() → uuid, evt iterator
  
  The loc-form methods (addNote/addCC/assignNote/assignCC/deleteNote/deleteCC)
  still exist alongside. These tests exercise the unified surface in isolation.

# Cases
  @case 'add(note): returns a uuid that resolves to the new note'  [harness]  @ 14-26
  @case 'add(cc/pb/pa/at/pc): every evType lands and is byUuid-addressable'  [harness]  @ 30-46
  @case 'assign: metadata-only change preserves the handle'  [harness]  @ 50-62
  @case 'assign: an identity-field change keeps the handle, which resolves to the moved note'  [harness]  @ 66-78
  @case 'assign: a cc identity change (chan or cc#) keeps the handle too'  [harness]  @ 82-92
  @case 'delete(uuid): event vanishes from byUuid and from the iterators'  [harness]  @ 96-118
  @case 'delete(unknown uuid): silent no-op'  [harness]  @ 122-131
  @case 'events(): yields all live events as (uuid, evt), notes then ccs'  [harness]  @ 135-158
  @case 'add(nil) / add{} / assign(nil, t): nil-paths return nil, no crash'  [harness]  @ 162-171

